{"path": "/tmp/isolated_workspace_1091/script.js", "content": "const DATA_URL = './data.json';
const DEFAULT_TIMEFRAME = 'weekly';

const timeframeLabels = {
  daily: 'Yesterday',
  weekly: 'Last Week',
  monthly: 'Last Month'
};

const activityMeta = {
  Work: {
    className: 'activity-card--work',
    icon: './time-tracking-dashboard-main/images/icon-work.svg'
  },
  Play: {
    className: 'activity-card--play',
    icon: './time-tracking-dashboard-main/images/icon-play.svg'
  },
  Study: {
    className: 'activity-card--study',
    icon: './time-tracking-dashboard-main/images/icon-study.svg'
  },
  Exercise: {
    className: 'activity-card--exercise',
    icon: './time-tracking-dashboard-main/images/icon-exercise.svg'
  },
  Social: {
    className: 'activity-card--social',
    icon: './time-tracking-dashboard-main/images/icon-social.svg'
  },
  'Self Care': {
    className: 'activity-card--self-care',
    icon: './time-tracking-dashboard-main/images/icon-self-care.svg'
  }
};

const state = {
  timeframe: DEFAULT_TIMEFRAME,
  activities: []
};

const cardsRoot = document.querySelector('#activity-cards');
const cardTemplate = document.querySelector('#activity-card-template');
const timeframeButtons = [...document.querySelectorAll('.timeframe-button')];

function formatHours(value) {
  return `${value}hr${value === 1 ? '' : 's'}`;
}

function createCard(activity) {
  const cardNode = cardTemplate.content.firstElementChild.cloneNode(true);
  const meta = activityMeta[activity.title] ?? {};
  const titleNode = cardNode.querySelector('.activity-card__title');
  const iconNode = cardNode.querySelector('.activity-card__icon');

  cardNode.classList.add(meta.className || '');
  cardNode.dataset.title = activity.title;
  titleNode.textContent = activity.title;

  if (meta.icon) {
    iconNode.src = meta.icon;
  }

  renderCardStats(cardNode, activity, state.timeframe);
  return cardNode;
}

function renderCardStats(cardNode, activity, timeframe) {
  const stats = activity.timeframes[timeframe];
  const currentNode = cardNode.querySelector('[data-role="current"]');
  const previousNode = cardNode.querySelector('[data-role="previous"]');

  currentNode.textContent = formatHours(stats.current);
  previousNode.textContent = `${timeframeLabels[timeframe]} - ${formatHours(stats.previous)}`;
}

function renderCards() {
  cardsRoot.innerHTML = '';
  const fragment = document.createDocumentFragment();

  state.activities.forEach((activity) => {
    fragment.appendChild(createCard(activity));
  });

  cardsRoot.appendChild(fragment);
}

function updateTimeframe(nextTimeframe) {
  state.timeframe = nextTimeframe;

  timeframeButtons.forEach((button) => {
    const active = button.dataset.timeframe === nextTimeframe;
    button.classList.toggle('is-active', active);
    button.setAttribute('aria-pressed', String(active));
  });

  document.querySelectorAll('.activity-card').forEach((cardNode) => {
    const activity = state.activities.find((item) => item.title === cardNode.dataset.title);
    if (activity) {
      renderCardStats(cardNode, activity, nextTimeframe);
    }
  });
}

async function loadActivities() {
  const response = await fetch(DATA_URL);
  if (!response.ok) {
    throw new Error(`Failed to load data: ${response.status}`);
  }

  return response.json();
}

function attachEvents() {
  timeframeButtons.forEach((button) => {
    button.addEventListener('click', () => {
      updateTimeframe(button.dataset.timeframe);
    });
  });
}

async function init() {
  try {
    state.activities = await loadActivities();
    renderCards();
    updateTimeframe(state.timeframe);
    attachEvents();
  } catch (error) {
    cardsRoot.innerHTML = `<p class="load-error">Unable to load dashboard data.</p>`;
    console.error(error);
  }
}

init();
"}

